/*******
 * Get percentage ONLY from TYPE="CARGO" inside CQP_COMMODITIES_FILTERED
 * based on CQP_TOTAL_IMPORTS_ANNUAL_USD range.
 *
 * @param none
 * @return (Number|null) percentage or null if no match
 *
 * by Adriana Centellas
 *******/

// 1) Get filtered commodities array
var filtered = this._parent.CQP_COMMODITIES_FILTERED || [];

// 2) Get value of total imports
var total = this.CQP_TOTAL_DOMESTIC_ANNUAL_USD;

total = Number(total);

if (isNaN(total)) {
  return null;
}

// 3) Find ONLY the CARGO object
var cargoItem = filtered.find(function (item) {
  return item && item.TYPE === "CARGO";
});

// If no cargo found, return null
if (!cargoItem || !cargoItem.LIMITS) {
  return null;
}

// 4) Search for matching band in cargo limits
for (var i = 0; i < cargoItem.LIMITS.length; i++) {
  var band = cargoItem.LIMITS[i];

  var min = Number(band.MIN);
  var max = Number(band.MAX);

  if (isNaN(min) || isNaN(max)) {
    continue;
  }

  if (total >= min && total <= max) {
    return band.PERCENTAGE; // ✓ Found the percentage
  }
}

// 5) No match found
return null;

